#!/usr/bin/env python3
"""TCG/Opal-document-sourced edge-case harness.

Unlike run_synthetic_edges.py, every case here includes source files from
/dl2026/skeleton/artifacts/documents that justify the expected PASS/FAIL label.
"""

from __future__ import annotations

import argparse
import copy
import importlib.util
import json
import hashlib
import re
import sys
from dataclasses import dataclass
from pathlib import Path
from typing import Any

ROOT = Path(__file__).resolve().parents[1]
if str(ROOT) not in sys.path:
    sys.path.insert(0, str(ROOT))

HELPER_PATH = Path(__file__).resolve().parent / "run_synthetic_edges.py"
HELPER_SPEC = importlib.util.spec_from_file_location("edge_helpers", HELPER_PATH)
if HELPER_SPEC is None or HELPER_SPEC.loader is None:
    raise RuntimeError(f"Cannot load helper module from {HELPER_PATH}")
edge_helpers = importlib.util.module_from_spec(HELPER_SPEC)
sys.modules[HELPER_SPEC.name] = edge_helpers
HELPER_SPEC.loader.exec_module(edge_helpers)

from src.solver import (  # noqa: E402
    FAIL,
    INVALID_PARAMETER,
    NOT_AUTHORIZED,
    SP_BUSY,
    SP_DISABLED,
    SP_FROZEN,
    SUCCESS,
    State,
    apply_transition,
    expected_status,
    parse_event,
    predict_trajectory,
)
from src.solver_components.constants import C_EC_DEFAULT_CURVE_COLUMNS  # noqa: E402


DOC_ROOT = "/dl2026/skeleton/artifacts/documents"
DEFAULT_CONSENSUS_MATRIX = ROOT / "analysis" / "label_consensus_matrix.json"


@dataclass(frozen=True)
class Evidence:
    sources: tuple[str, ...]
    rule: str


@dataclass(frozen=True)
class Case:
    name: str
    trajectory: list[dict[str, Any]]
    expected: str
    evidence: Evidence
    tag: str
    rule_id: str = ""
    concepts: tuple[str, ...] = ()
    repair_paths: tuple[str, ...] = ()
    repair_hint: str = ""


def source(*paths: str, rule: str) -> Evidence:
    return Evidence(tuple(f"{DOC_ROOT}/{path}" for path in paths), rule)


