def _rule_id_from(evidence: Evidence, tag: str) -> str:
    joined = "|".join(evidence.sources) + "\n" + evidence.rule
    return f"{_slugify(tag)}-{hashlib.sha1(joined.encode('utf-8')).hexdigest()[:8]}"


def case(
    name: str,
    trajectory: list[dict[str, Any]],
    expected: str,
    evidence: Evidence,
    tag: str,
    *,
    rule_id: str | None = None,
    concepts: tuple[str, ...] | None = None,
    repair_paths: tuple[str, ...] | None = None,
    repair_hint: str | None = None,
) -> Case:
    metadata = TAG_METADATA.get(tag, {})
    return Case(
        name=name,
        trajectory=trajectory,
        expected=expected,
        evidence=evidence,
        tag=tag,
        rule_id=rule_id or _rule_id_from(evidence, tag),
        concepts=concepts or tuple(metadata.get("concepts", (tag,))),
        repair_paths=repair_paths or tuple(metadata.get("repair_paths", ())),
        repair_hint=repair_hint if repair_hint is not None else str(metadata.get("repair_hint", "")),
    )


def _slugify(text: str) -> str:
    lowered = text.lower()
    cleaned = re.sub(r"[^a-z0-9]+", "-", lowered).strip("-")
    return cleaned[:40] or "case"


def case_id(case_item: Case) -> str:
    digest = hashlib.sha1(f"{case_item.tag}\n{case_item.name}".encode("utf-8")).hexdigest()[:10]
    return f"{_slugify(case_item.tag)}-{digest}"


def consensus_accepted_ids(matrix_path: Path = DEFAULT_CONSENSUS_MATRIX) -> set[str]:
    if not matrix_path.exists():
        raise FileNotFoundError(
            f"Consensus matrix not found: {matrix_path}. Run `python tools/label_consensus.py report` first."
        )
    rows = json.loads(matrix_path.read_text(encoding="utf-8"))
    return {str(row["case_id"]) for row in rows if row.get("status") == "accepted"}


def h(name: str) -> Any:
    return getattr(edge_helpers, name)


def append_status_pair(
    cases: list[Case],
    *,
    name: str,
    context: list[dict[str, Any]],
    target_factory,
    correct_status: str,
    evidence: Evidence,
    tag: str,
    rule_id: str | None = None,
    concepts: tuple[str, ...] | None = None,
    repair_paths: tuple[str, ...] | None = None,
    repair_hint: str | None = None,
) -> None:
    cases.append(
        case(
            f"{name}: correct status",
            context + [target_factory(correct_status)],
            "PASS",
            evidence,
            tag,
            rule_id=rule_id,
            concepts=concepts,
            repair_paths=repair_paths,
            repair_hint=repair_hint,
        )
    )
    cases.append(
        case(
            f"{name}: impossible success",
            context + [target_factory(SUCCESS)],
            "FAIL",
            evidence,
            tag,
            rule_id=rule_id,
            concepts=concepts,
            repair_paths=repair_paths,
            repair_hint=repair_hint,
        )
    )


