def activated_locking_context() -> list[dict[str, Any]]:
    return h("activated_locking_context")()


def locking_admin_open() -> list[dict[str, Any]]:
    return h("locking_admin_open")()


def manufactured_inactive_activated_locking_context() -> list[dict[str, Any]]:
    return h("owned_admin_context")() + [
        h("start_session")(h("ADMIN_SP"), h("SID"), "new"),
        h("method_record")("Get", h("LOCKING_SP"), "SP", return_values={"LifeCycle": "Manufactured-Inactive"}),
        h("method_record")("Activate", h("LOCKING_SP"), "SP"),
        h("end_session")(),
    ]


def locked_range(
    *,
    start: int = 80,
    length: int = 8,
    read_enabled: int = 1,
    write_enabled: int = 1,
    read_locked: int = 0,
    write_locked: int = 0,
    lock_on_reset: Any | None = None,
) -> list[dict[str, Any]]:
    values: dict[int, Any] = {
        3: start,
        4: length,
        5: read_enabled,
        6: write_enabled,
        7: read_locked,
        8: write_locked,
    }
    if lock_on_reset is not None:
        values[9] = lock_on_reset
    return locking_admin_open() + [h("set_values")(h("LOCKING_RANGE1"), "Locking", values), h("end_session")()]


def mbr_active_context(done: int = 0) -> list[dict[str, Any]]:
    return activated_locking_context() + [
        h("host_write")("AA", lba="0"),
        h("start_session")(h("LOCKING_SP"), h("ADMIN1"), "new"),
        h("set_values")(h("MBR_CONTROL"), "MBRControl", {1: 1, 2: done}),
        h("end_session")(),
    ]


def mbr_table_payload_context(*, payload: str = "B0", prior_pattern: str | None = "AA", done: int = 0) -> list[dict[str, Any]]:
    context = activated_locking_context()
    if prior_pattern is not None:
        context.append(h("host_write")(prior_pattern, lba="0"))
    context.extend(
        [
            h("start_session")(h("LOCKING_SP"), h("ADMIN1"), "new"),
            h("method_record")("Set", "0000080400000000", "MBR", optional={"Bytes": payload}),
            h("set_values")(h("MBR_CONTROL"), "MBRControl", {1: 1, 2: done}),
            h("end_session")(),
        ]
    )
    return context


def mbr_bytes_set(payload: str, *, start_row: int | None = None, status: str = SUCCESS) -> dict[str, Any]:
    if start_row is not None:
        return h("raw_method_record")(
            "Set",
            "0000080400000000",
            "MBR",
            status=status,
            args=[("startRow", start_row), ("Bytes", payload)],
            return_values=[],
        )
    return h("method_record")("Set", "0000080400000000", "MBR", status=status, optional={"Bytes": payload}, return_values=[])


def mbr_bytes_get(start_row: int, end_row: int, *, status: str = SUCCESS, return_values: Any = "AA") -> dict[str, Any]:
    return h("raw_method_record")(
        "Get",
        "0000080400000000",
        "MBR",
        status=status,
        args=[(1, start_row), (2, end_row)],
        return_values=return_values,
    )


def mbr_bytes_get_cellblock(start_row: int, end_row: int, *, status: str = SUCCESS, return_values: Any = "AA") -> dict[str, Any]:
    return h("method_record")(
        "Get",
        "0000080400000000",
        "MBR",
        status=status,
        required={"Cellblock": [{"startRow": start_row}, {"endRow": end_row}]},
        return_values=return_values,
    )


def mbr_active_locked_outside_context(done: int = 0) -> list[dict[str, Any]]:
    return activated_locking_context() + [
        h("start_session")(h("LOCKING_SP"), h("ADMIN1"), "new"),
        h("set_values")(h("MBR_CONTROL"), "MBRControl", {1: 1, 2: done}),
        h("set_values")(
            h("LOCKING_RANGE1"),
            "Locking",
            {3: 300000, 4: 8, 5: 1, 6: 0, 7: 1, 8: 0},
        ),
        h("end_session")(),
    ]


def mbr_active_outside_range_context(
    *,
    done: int = 0,
    read_enabled: int = 0,
    write_enabled: int = 0,
    read_locked: int = 0,
    write_locked: int = 0,
    remembered_pattern: str | None = None,
) -> list[dict[str, Any]]:
    context = activated_locking_context() + [
        h("start_session")(h("LOCKING_SP"), h("ADMIN1"), "new"),
        h("set_values")(h("MBR_CONTROL"), "MBRControl", {1: 1, 2: done}),
        h("set_values")(
            h("LOCKING_RANGE1"),
            "Locking",
            {
                3: 300000,
                4: 8,
                5: read_enabled,
                6: write_enabled,
                7: read_locked,
                8: write_locked,
            },
        ),
        h("end_session")(),
    ]
    if remembered_pattern is not None:
        context.append(h("host_write")(remembered_pattern, lba="300000 ~ 300007"))
    return context


def create_locking_row(
    *,
    start: int,
    length: int,
    status: str = SUCCESS,
    returned_uid: str = "0000080200030001",
) -> dict[str, Any]:
    return h("method_record")(
        "CreateRow",
        "0000080200000000",
        "Locking",
        status,
        optional={"Row": [{"3": start}, {"4": length}]},
        return_values=[returned_uid] if status == SUCCESS else [],
    )


def locking_info_alignment_context(
    *,
    alignment_required: int = 1,
    logical_block_size: int | None = None,
    granularity: int = 8,
    lowest: int = 4,
) -> list[dict[str, Any]]:
    returned = {
        "AlignmentRequired": alignment_required,
        "AlignmentGranularity": granularity,
        "LowestAlignedLBA": lowest,
    }
    if logical_block_size is not None:
        returned["LogicalBlockSize"] = logical_block_size
    return locking_admin_open() + [
        h("method_record")(
            "Get",
            "0000080100000000",
            "LockingInfo",
            return_values=returned,
        )
    ]


def locking_range_reencrypt_state_context(state_value: Any) -> list[dict[str, Any]]:
    return locking_admin_open() + [
        h("method_record")(
            "Get",
            h("LOCKING_RANGE1"),
            "Locking",
            return_values=[[{"12": state_value}]],
        )
    ]


def reencrypt_empty_cont_on_reset_context(state_value: Any) -> list[dict[str, Any]]:
    return locking_admin_open() + [
        h("method_record")(
            "Get",
            h("LOCKING_RANGE1"),
            "Locking",
            return_values=[[{"12": state_value}, {"16": []}]],
        ),
        h("end_session")(),
        h("host_reset")("PowerCycle"),
        h("start_session")(h("LOCKING_SP"), h("ADMIN1"), "new"),
    ]


def locking_global_reencrypt_state_context(state_value: Any) -> list[dict[str, Any]]:
    return locking_admin_open() + [
        h("method_record")(
            "Get",
            "0000080200000001",
            "Locking",
            return_values=[[{"12": state_value}]],
        )
    ]


def global_range_revertsp_context(
    *,
    read_locked: int = 0,
    write_locked: int = 0,
    remembered_pattern: str = "AA",
) -> list[dict[str, Any]]:
    return manufactured_inactive_activated_locking_context() + [
        h("host_write")(remembered_pattern, lba="200 ~ 207"),
        h("start_session")(h("LOCKING_SP"), h("ADMIN1"), "new"),
        h("set_values")(
            "0000080200000001",
            "Locking",
            {5: 1, 6: 1, 7: read_locked, 8: write_locked},
        ),
    ]


def user_try_limit_context(*, try_limit: int, persistence: int = 1, failures: int = 0) -> list[dict[str, Any]]:
    context = locking_admin_open() + [
        h("set_values")("", "User1", {5: 1}),
        h("set_values")("", "C_PIN_User1", {3: "userpin", 5: try_limit, 7: persistence}),
        h("end_session")(),
    ]
    context.extend(
        h("start_session")(h("LOCKING_SP"), "User1", f"bad{idx}", status=NOT_AUTHORIZED)
        for idx in range(failures)
    )
    return context


def user1_disabled_context(*, pin: str = "userpin") -> list[dict[str, Any]]:
    return locking_admin_open() + [
        h("set_values")("", "User1", {5: 0}),
        h("set_values")("", "C_PIN_User1", {3: pin}),
        h("end_session")(),
    ]


def user1_authority_limit_context(*, limit: int, uses: int, keep_open: bool = False, pin: str = "userpin") -> list[dict[str, Any]]:
    context = activated_locking_context() + [
        h("start_session")(h("LOCKING_SP"), h("ADMIN1"), "new"),
        h("set_values")("0000000900030001", "Authority", {5: 1}),
        h("set_values")("0000000B00030001", "C_PIN", {3: pin}),
        h("method_record")("Get", "0000000900030001", "Authority", return_values={"Limit": limit, "Uses": uses}),
    ]
    if not keep_open:
        context.append(h("end_session")())
    return context


def authenticate_user1(*, status: str = SUCCESS, result: bool | None = None, challenge: str = "userpin") -> dict[str, Any]:
    return_values = [] if result is None else [result]
    return h("method_record")(
        "Authenticate",
        "0000000000000001",
        "ThisSP",
        status=status,
        required={"Authority": "User1", "Challenge": challenge},
        return_values=return_values,
    )


def authenticate_authority(
    authority: str,
    *,
    status: str = SUCCESS,
    result: bool | None = None,
    challenge: str = "proof",
) -> dict[str, Any]:
    return_values = [] if result is None else [result]
    return h("method_record")(
        "Authenticate",
        "0000000000000001",
        "ThisSP",
        status=status,
        required={"Authority": authority, "Challenge": challenge},
        return_values=return_values,
    )


