        "core/5.3.2.8.txt",
        "core/5.3.2.8.2.txt",
        "core/5.3.2.8.3.txt",
        "core/5.3.2.8.4.txt",
        "core/5.7.2.3.txt",
        "core/5.7.2.3.4.txt",
        "core/5.7.2.3.5.txt",
        "core/5.7.2.4.txt",
