    def properties_response(values: dict[str, Any]) -> dict[str, Any]:
        return h("method_record")(
            "Properties",
            "00000000000000FF",
            "Session Manager UID",
            status=SUCCESS,
            return_values=values,
        )

    def admin_sp_session_timeout_context(
        *,
        sp_timeout: int,
        max_timeout: int,
        min_timeout: int = 0,
        def_timeout: int = 0,
    ) -> list[dict[str, Any]]:
        return h("owned_admin_context")() + [
            properties_response(
                {
                    "DefSessionTimeout": def_timeout,
                    "MaxSessionTimeout": max_timeout,
                    "MinSessionTimeout": min_timeout,
                }
            ),
            h("start_session")(h("ADMIN_SP"), h("SID"), "new"),
            h("set_values")("0000000200000001", "SPInfo", {5: sp_timeout}),
            h("end_session")(),
        ]

    def trans_timeout_context(*, max_timeout: int, min_timeout: int, def_timeout: int = 0) -> list[dict[str, Any]]:
        return h("owned_admin_context")() + [
            properties_response(
                {
                    "DefTransTimeout": def_timeout,
                    "MaxTransTimeout": max_timeout,
                    "MinTransTimeout": min_timeout,
                }
            )
        ]

    def start_session_with_optional(optional: dict[str, Any], *, status: str = SUCCESS) -> dict[str, Any]:
        return h("method_record")(
            "StartSession",
            "00000000000000FF",
            "Session Manager UID",
            status=status,
            required={"SPID": h("ADMIN_SP"), "Write": 1},
            optional=optional,
            return_values={"required": {"HostSessionID": "00000001", "SPSessionID": "00000001"}, "optional": {}}
            if status == SUCCESS
            else [],
        )

    def start_session_success_with_optional(optional: dict[str, Any]) -> dict[str, Any]:
        return start_session_with_optional(optional, status=SUCCESS)

    def syncsession_return(
        *,
        host_session_id: Any | None = "00000001",
        sp_session_id: Any | None = "00000001",
        optional: dict[str, Any] | None = None,
    ) -> dict[str, Any]:
        required: dict[str, Any] = {}
        if host_session_id is not None:
            required["HostSessionID"] = host_session_id
        if sp_session_id is not None:
            required["SPSessionID"] = sp_session_id
        return {"required": required, "optional": optional or {}}

    def start_session_with_return(
        *,
        optional: dict[str, Any] | None = None,
        return_values: Any | None = None,
        status: str = SUCCESS,
    ) -> dict[str, Any]:
        return h("method_record")(
            "StartSession",
            "00000000000000FF",
            "Session Manager UID",
            status=status,
            required={"SPID": h("ADMIN_SP"), "Write": 1},
            optional=optional or {},
            return_values=syncsession_return() if return_values is None and status == SUCCESS else return_values or [],
        )

    def start_session_with_host_session_id(
        host_session_id: Any,
        returned_host_session_id: Any,
        *,
        optional: dict[str, Any] | None = None,
        sp_session_id: Any = "00000001",
        status: str = SUCCESS,
    ) -> dict[str, Any]:
        return h("method_record")(
            "StartSession",
            "00000000000000FF",
            "Session Manager UID",
            status=status,
            required={"HostSessionID": host_session_id, "SPID": h("ADMIN_SP"), "Write": 1},
            optional=optional or {},
            return_values=syncsession_return(host_session_id=returned_host_session_id, sp_session_id=sp_session_id)
            if status == SUCCESS
            else [],
        )

    def start_session_with_write(write_value: Any, *, status: str = SUCCESS) -> dict[str, Any]:
        return h("method_record")(
            "StartSession",
            "00000000000000FF",
            "Session Manager UID",
            status=status,
            required={"SPID": h("ADMIN_SP"), "Write": write_value},
            return_values=syncsession_return() if status == SUCCESS else [],
        )

    def trans_credit_start(
        request_trans: Any | None,
        returned: dict[str, Any],
        *,
        status: str = SUCCESS,
    ) -> dict[str, Any]:
        optional: dict[str, Any] = {}
        if request_trans is not None:
            optional["TransTimeout"] = request_trans
        return start_session_with_return(
            optional=optional,
            return_values=syncsession_return(optional=returned),
            status=status,
        )

    def sid_start_session(status: str = SUCCESS, *, signed_hash: str | None = None) -> dict[str, Any]:
        optional: dict[str, Any] = {"HostSigningAuthority": h("SID"), "HostChallenge": "new"}
        if signed_hash is not None:
            optional["SignedHash"] = signed_hash
        return start_session_with_optional(optional, status=status)

    def sid_start_session_with_ids(host_session_id: Any, sp_session_id: Any, *, status: str = SUCCESS, comid: Any | None = None) -> dict[str, Any]:
        optional = {"HostSigningAuthority": h("SID"), "HostChallenge": "new"}
        if comid is not None:
            optional["ComID"] = comid
        return h("method_record")(
            "StartSession",
            "00000000000000FF",
            "Session Manager UID",
            status=status,
            required={"SPID": h("ADMIN_SP"), "Write": 1},
            optional=optional,
            return_values={"required": {"HostSessionID": host_session_id, "SPSessionID": sp_session_id}, "optional": {}}
            if status == SUCCESS
            else [],
        )

    def start_trusted_with_ids(
        host_session_id: Any,
        sp_session_id: Any,
        *,
        status: str = SUCCESS,
        target_uid: str = "00000000000000FF",
        target_name: str = "Session Manager UID",
        host_response: Any | None = None,
        return_values: Any | None = None,
    ) -> dict[str, Any]:
        required: dict[str, Any] = {"HostSessionID": host_session_id, "SPSessionID": sp_session_id}
        if host_response is not None:
            required["HostResponse"] = host_response
        return h("method_record")(
            "StartTrustedSession",
            target_uid,
            target_name,
            status=status,
            required=required,
            return_values=[] if return_values is None else return_values,
        )

    def sid_hash_and_sign_set_context(value: Any) -> list[dict[str, Any]]:
        return h("owned_admin_context")() + [
            h("start_session")(h("ADMIN_SP"), h("SID"), "new"),
            h("set_values")("0000000900000006", "Authority_SID", {7: value}),
            h("end_session")(),
        ]

    def sid_hash_and_sign_get_context(value: Any) -> list[dict[str, Any]]:
        return h("owned_admin_context")() + [
            h("start_session")(h("ADMIN_SP"), h("SID"), "new"),
            h("method_record")("Get", "0000000900000006", "Authority_SID", return_values={"HashAndSign": value}),
            h("end_session")(),
        ]

    def authority_get(authority_uid: str, values: dict[int, Any]) -> dict[str, Any]:
        return h("method_record")("Get", authority_uid, "Authority", return_values={str(key): value for key, value in values.items()})

    def sid_authority_get_context(*observations: dict[int, Any]) -> list[dict[str, Any]]:
        trajectory = h("owned_admin_context")() + [h("start_session")(h("ADMIN_SP"), h("SID"), "new")]
        trajectory.extend(authority_get(h("SID"), values) for values in observations)
        trajectory.append(h("end_session")())
        return trajectory

    def sid_authority_set_context(*updates: dict[int, Any]) -> list[dict[str, Any]]:
        trajectory = h("owned_admin_context")() + [h("start_session")(h("ADMIN_SP"), h("SID"), "new")]
        trajectory.extend(h("set_values")("0000000900000006", "Authority_SID", values) for values in updates)
        trajectory.append(h("end_session")())
        return trajectory

    def adminexch_ecmqv_context() -> list[dict[str, Any]]:
        return h("owned_admin_context")() + [
            h("start_session")(h("ADMIN_SP"), h("SID"), "new"),
            authority_get("0000000900000009", {5: True, 9: "Exchange", 10: "C_EC_256_AdminExch"}),
            h("end_session")(),
        ]

    def adminexch_ecmqv_start(returned: dict[str, Any]) -> dict[str, Any]:
        return start_session_with_return(
            optional={
                "HostExchangeAuthority": "AdminExch",
                "HostChallenge": "host-ephemeral",
                "HostExchangeCert": "host-static",
            },
            return_values=syncsession_return(optional=returned),
        )

