    def admin_sid_session() -> list[dict[str, Any]]:
        return h("owned_admin_context")() + [h("start_session")(h("ADMIN_SP"), h("SID"), "new")]

    def cec_created_row_context(family: str, row_uid: str) -> list[dict[str, Any]]:
        first_non_default_column = max(C_EC_DEFAULT_CURVE_COLUMNS[family]) + 1
        supplied_non_curve_values = [
            {str(first_non_default_column): "11"},
            {str(first_non_default_column + 1): "22"},
            {str(first_non_default_column + 2): "33"},
            {str(first_non_default_column + 3): "SHA_256"},
            {str(first_non_default_column + 4): 0},
            {str(first_non_default_column + 5): "0000000000000000"},
        ]
        return admin_sid_session() + [
            h("method_record")(
                "CreateRow",
                "",
                f"{family}Table",
                status=SUCCESS,
                optional={
                    "Row": [
                        {"1": f"{family}_DocDefault"},
                        {"2": f"{family}_DocDefault"},
                        *supplied_non_curve_values,
                    ]
                },
                return_values=[row_uid],
            )
        ]

    def cec_curve_get(family: str, row_uid: str, values: dict[int, Any]) -> dict[str, Any]:
        return h("method_record")(
            "Get",
            row_uid,
            f"{family}_DocDefault",
            status=SUCCESS,
            required={"CellBlock": [{"startColumn": 3}, {"endColumn": 7}]},
            return_values=[[{str(column): value} for column, value in sorted(values.items())]],
        )

    for family, row_uid in [
        ("C_EC_160", "0000000D00000160"),
        ("C_EC_192", "0000000D00000192"),
        ("C_EC_224", "0000000D00000224"),
        ("C_EC_384", "0000000D00000384"),
    ]:
        defaults = dict(C_EC_DEFAULT_CURVE_COLUMNS[family])
        wrong_defaults = dict(defaults)
        wrong_defaults[3] = "0"
        append_return_value_pair(
            cases,
            name=f"{family} CreateRow omitted curve columns default into later Get",
            context=cec_created_row_context(family, row_uid),
            correct_target=cec_curve_get(family, row_uid, defaults),
            wrong_target=cec_curve_get(family, row_uid, wrong_defaults),
            evidence=cec_default_curve_docs,
            tag="cec-default-curve-values-doc",
        )

    for family, row_uid in [
        ("C_EC_521", "0000000D00000521"),
        ("C_EC_163", "0000000D00010163"),
        ("C_EC_233", "0000000D00010233"),
        ("C_EC_283", "0000000D00010283"),
    ]:
        defaults = dict(C_EC_DEFAULT_CURVE_COLUMNS[family])
        wrong_defaults = dict(defaults)
        wrong_defaults[min(defaults)] = "0"
        append_return_value_pair(
            cases,
            name=f"{family} CreateRow omitted table-specific curve columns default into later Get",
            context=cec_created_row_context(family, row_uid),
            correct_target=cec_curve_get(family, row_uid, defaults),
            wrong_target=cec_curve_get(family, row_uid, wrong_defaults),
            evidence=cec_default_curve_expanded_docs,
            tag="cec-default-curve-values-expanded-tight-doc",
        )

