    def authenticate_user1_proof(*, status: str = SUCCESS, result: bool | None = None, proof: str = "userpin") -> dict[str, Any]:
        return h("method_record")(
            "Authenticate",
            "0000000000000001",
            "ThisSP",
            status=status,
            required={"Authority": "User1"},
            optional={"Proof": proof},
            return_values=[] if result is None else [result],
        )

