    def host_props_response(
        submitted: dict[str, Any],
        returned: dict[str, Any],
        *,
        status: str = SUCCESS,
        comid: Any | None = None,
    ) -> dict[str, Any]:
        optional = {"HostProperties": submitted}
        if comid is not None:
            optional["ComID"] = comid
        return h("method_record")(
            "Properties",
            "00000000000000FF",
            "Session Manager UID",
            status=status,
            optional=optional,
            return_values={"HostProperties": returned} if status == SUCCESS else [],
        )

