    def range1_geometry_data_context(
        *,
        start: int,
        length: int,
        pattern: str,
        lba: str,
        updates: list[tuple[dict[int, Any], str]],
        extra_rows: list[dict[str, Any]] | None = None,
    ) -> list[dict[str, Any]]:
        context = locking_admin_open() + [
            create_locking_row(start=start, length=length, returned_uid=h("LOCKING_RANGE1")),
        ]
        context.extend(extra_rows or [])
        context.extend(
            [
                h("end_session")(),
                h("host_write")(pattern, lba=lba),
                h("start_session")(h("LOCKING_SP"), h("ADMIN1"), "new"),
            ]
        )
        context.extend(
            h("set_values")(h("LOCKING_RANGE1"), "Locking", values, status=status)
            for values, status in updates
        )
        context.append(h("end_session")())
        return context

