    def clock_method_record(method_name: str, *, status: str = SUCCESS) -> dict[str, Any]:
        required: dict[str, Any] = {}
        if method_name in {"SetClockHigh", "SetClockLow"}:
            required = {"ExactTime": {"Year": 2026, "Month": 5, "Day": 31}}
        elif method_name in {"SetLagHigh", "SetLagLow"}:
            required = {"LagTime": {"Seconds": 1, "Fraction": 0}}
        return h("method_record")(
            method_name,
            "0000040100000001",
            "ClockTime",
            status=status,
            required=required,
            return_values=[],
        )

