    def opal_v2_feature_descriptor(*, sid_revert_behavior: int = 0) -> dict[str, Any]:
        return {
            "input": {
                "command": "Level0Discovery",
                "args": {"FeatureCode": "0x0203", "Feature": "Opal SSC V2"},
            },
            "output": {
                "status": SUCCESS,
                "return_values": {
                    "FeatureCode": "0x0203",
                    "FeatureDescriptorVersion": 2,
                    "SSCMinorVersion": 3,
                    "Length": 0x10,
                    "NumberOfComIDs": 1,
                    "RangeCrossingBehavior": 0,
                    "NumberOfLockingSPAdminAuthorities": 4,
                    "NumberOfLockingSPUserAuthorities": 8,
                    "InitialCPINSIDPINIndicator": 0,
                    "BehaviorOfCPINSIDPINUponTPerRevert": sid_revert_behavior,
                },
            },
        }

