    def acl_method(method: str, required: dict[str, Any] | None = None, optional: dict[str, Any] | None = None, *, status: str = SUCCESS, return_values: Any | None = None, target: str = "AccessControl") -> dict[str, Any]:
        return h("method_record")(
            method,
            "0000000700000000" if target == "AccessControl" else "0000000B00030001",
            target,
            status=status,
            required=required or {},
            optional=optional or {},
            return_values=[] if return_values is None else return_values,
        )

    def admin_acl_session() -> list[dict[str, Any]]:
        return h("owned_admin_context")() + [h("start_session")(h("ADMIN_SP"), h("SID"), "new")]

    def locking_acl_session() -> list[dict[str, Any]]:
        return h("activated_locking_context")() + [h("start_session")(h("LOCKING_SP"), h("ADMIN1"), "new")]

    def delete_locking_range_row(range_uid: str, *, status: str = SUCCESS) -> dict[str, Any]:
        return h("method_record")(
            "DeleteRow",
            "0000080200000000",
            "Locking",
            status=status,
            required={"Rows": [range_uid]},
            return_values=[],
        )

    def locking_range_direct_method(
        method: str,
        range_uid: str,
        *,
        status: str = SUCCESS,
        optional: dict[str, Any] | None = None,
        return_values: Any | None = None,
    ) -> dict[str, Any]:
        return h("method_record")(
            method,
            range_uid,
            "Locking",
            status=status,
            optional=optional or {},
            return_values=[] if return_values is None else return_values,
        )

