def state_before_target(trajectory: list[dict[str, Any]]) -> State:
    state = State()
    for raw in trajectory[:-1]:
        apply_transition(state, parse_event(raw))
    return state


def explain_failure(case_item: Case, got: str) -> dict[str, Any]:
    state = state_before_target(case_item.trajectory)
    target_raw = case_item.trajectory[-1]
    target = parse_event(target_raw)
    expected = expected_status(copy.deepcopy(state), target)
    return {
        "case": case_item.name,
        "tag": case_item.tag,
        "rule_id": case_item.rule_id,
        "concepts": case_item.concepts,
        "repair": {
            "paths": case_item.repair_paths,
            "hint": case_item.repair_hint,
        },
        "expected_verdict_from_docs": case_item.expected,
        "solver_verdict": got,
        "evidence": {
            "sources": case_item.evidence.sources,
            "rule": case_item.evidence.rule,
        },
        "solver_expected": {
            "allowed_statuses": sorted(str(item) for item in expected.allowed_statuses),
            "forbidden_statuses": sorted(str(item) for item in expected.forbidden_statuses),
            "expected_read_result": expected.expected_read_result,
            "forbidden_read_result": expected.forbidden_read_result,
            "forbid_read_result_presence": expected.forbid_read_result_presence,
            "reason": expected.reason,
            "confidence": expected.confidence,
        },
        "target_event": {
            "kind": target.kind,
            "method": target.method,
            "invoking_symbol": target.invoking_symbol,
            "status": target.status,
            "lba": target.lba,
            "read_result": target.read_result,
            "values": dict(target.values),
        },
        "target_raw": target_raw,
    }


def run(
    cases: list[Case],
    *,
    tag: str | None = None,
    jsonl: bool = False,
    consensus_gate: bool = False,
    consensus_matrix: Path = DEFAULT_CONSENSUS_MATRIX,
) -> int:
    selected = [item for item in cases if tag is None or item.tag == tag]
    if consensus_gate:
        accepted = consensus_accepted_ids(consensus_matrix)
        before = len(selected)
        selected = [item for item in selected if case_id(item) in accepted]
        if not jsonl:
            print(f"consensus gate: selected {len(selected)} accepted case(s) out of {before}")
    failures: list[dict[str, Any]] = []
    tag_counts: dict[str, int] = {}
    for item in selected:
        tag_counts[item.tag] = tag_counts.get(item.tag, 0) + 1
        got = predict_trajectory(item.trajectory)
        if got != item.expected:
            failures.append(explain_failure(item, got))

    if jsonl:
        for failure in failures:
            print(json.dumps(failure, ensure_ascii=False, default=str))
    else:
        print(f"sourced edge cases: {len(selected)}")
        print("by tag:", json.dumps(tag_counts, sort_keys=True))
        print(f"mismatches: {len(failures)}")
        for failure in failures:
            print("\n--- mismatch ---")
            print(json.dumps(failure, ensure_ascii=False, indent=2, default=str))
    return 1 if failures else 0


def main() -> None:
    parser = argparse.ArgumentParser()
    parser.add_argument("--tag")
    parser.add_argument("--jsonl", action="store_true")
    parser.add_argument("--consensus-gate", action="store_true", help="Run only cases accepted by independent label consensus.")
    parser.add_argument("--consensus-matrix", type=Path, default=DEFAULT_CONSENSUS_MATRIX)
    args = parser.parse_args()
    raise SystemExit(
        run(
            build_cases(),
            tag=args.tag,
            jsonl=args.jsonl,
            consensus_gate=args.consensus_gate,
            consensus_matrix=args.consensus_matrix,
        )
    )


if __name__ == "__main__":
    main()
